 1	import React, { Dispatch, FC, MouseEvent, SetStateAction, useState } from 'react';
 2	
 3	import SelectToggle from '@kubevirt-utils/components/toggles/SelectToggle';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { FormGroup } from '@patternfly/react-core';
 6	import { Select, SelectOption } from '@patternfly/react-core';
 7	
 8	import { AffinityRowData, AffinityType } from '../../../../utils/types';
 9	import { AFFINITY_TYPE_LABLES } from '../../../AffinityList/utils/constants';
10	
11	type AffinityTypeSelectProps = {
12	  focusedAffinity: AffinityRowData;
13	  setFocusedAffinity: Dispatch<SetStateAction<AffinityRowData>>;
14	};
15	
16	const AffinityTypeSelect: FC<AffinityTypeSelectProps> = ({
17	  focusedAffinity,
18	  setFocusedAffinity,
19	}) => {
20	  const { t } = useKubevirtTranslation();
21	  const [isOpen, setIsOpen] = useState(false);
22	
23	  const handleChange = (event: MouseEvent<HTMLSelectElement>, value: AffinityType) => {
24	    event.preventDefault();
25	    setFocusedAffinity({ ...focusedAffinity, type: value });
26	    setIsOpen(false);
27	  };
28	
29	  const onToggle = () => setIsOpen((prevIsOpen) => !prevIsOpen);
30	  return (
31	    <FormGroup fieldId="type" isRequired label={t('Type')}>
32	      <Select
33	        toggle={SelectToggle({
34	          isExpanded: isOpen,
35	          onClick: onToggle,
36	          selected: AFFINITY_TYPE_LABLES[focusedAffinity?.type],
37	        })}
38	        isOpen={isOpen}
39	        onSelect={handleChange}
40	        selected={focusedAffinity?.type}
41	      >
42	        {Object.entries(AFFINITY_TYPE_LABLES).map(([key, value]) => (
43	          <SelectOption key={key} value={key}>
44	            {value}
45	          </SelectOption>
46	        ))}
47	      </Select>
48	    </FormGroup>
49	  );
50	};
51	
52	export default AffinityTypeSelect;

